#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""deploy_ui.py — Part B(2/2) UI 四件套

1. i18n.py(新): agent 名中文化 + reasoning 术语翻译（重建 v3.5 丢失的 i18n）。
2. decision_summary.py: 结论里 agent 名/术语接 i18n（中英混杂收口）。
3. web_app.py(重写): K线图(红涨绿跌+MA5/20/60) + 修复观察池渲染(v_pool/t_pool/n_pool,
   原 JS 找 d.entries 永远显示空) + 日报入库路由&UI + AGENT_ZH 注入 + 顶部 inject_no_proxy。
4. seed_pool.py(新): V/T/N 15票播种(部署末尾自动执行, 旧池自动备份)。
5. ingest_briefing_cli.py(新): 日报命令行入口(文件/粘贴/stdin)。

用法: poetry run python deploy_ui.py      回滚: deploy_backup/<时间戳>/ 覆盖回去
"""
import base64, os, sys, shutil
from datetime import datetime

FILES = {
    'src/utils/i18n.py': "",
    'src/utils/decision_summary.py': "",
    'src/web_app.py': "",
    'seed_pool.py': "",
    'ingest_briefing_cli.py': "",
}

def main():
    root = os.getcwd()
    if not os.path.isdir(os.path.join(root, "src")):
        print("[FAIL] 请在项目根目录(含 src/)运行"); sys.exit(1)
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    bdir = os.path.join(root, "deploy_backup", ts); os.makedirs(bdir, exist_ok=True)
    for rel, b64 in FILES.items():
        dst = os.path.join(root, *rel.split("/"))
        if os.path.exists(dst):
            shutil.copy2(dst, os.path.join(bdir, rel.replace("/", "__")))
        os.makedirs(os.path.dirname(dst) or ".", exist_ok=True)
        with open(dst, "wb") as f:
            f.write(base64.b64decode(b64))
        print(f"[OK] 写入 {rel}")
    print(f"[OK] 备份 -> deploy_backup/{ts}/")
    n = 0
    for r,_,_ in os.walk(os.path.join(root,"src")):
        if r.endswith("__pycache__"): shutil.rmtree(r, ignore_errors=True); n+=1
    print(f"[OK] 清理 {n} 个 __pycache__")
    verify(root)

def verify(root):
    import py_compile
    print("-"*60); print("验证:")
    sys.path.insert(0, root)
    # web_app 只编译(避免依赖 fastapi 才能 import)
    try:
        py_compile.compile(os.path.join(root,"src","web_app.py"), doraise=True)
        print("  [PASS] web_app.py 编译通过")
    except Exception as e:
        print(f"  [FAIL] web_app.py 编译失败: {e}"); sys.exit(1)
    try:
        for m in [m for m in list(sys.modules) if "utils.i18n" in m]: del sys.modules[m]
        from src.utils.i18n import agent_name_zh, localize_reasoning
        assert agent_name_zh("nassim_taleb") == "塔勒布尾部风险"
        assert "尾部风险" in localize_reasoning("tail risk")
        print("  [PASS] i18n: agent 名 + reasoning 术语中文化")
    except Exception as e:
        print(f"  [FAIL] i18n: {e}"); sys.exit(1)
    # 自动播种池(他已确认用 watchlist 播种; save_pool_state 会备份旧池)
    try:
        import importlib
        sp = importlib.import_module("seed_pool")
        sp.main()
        from src.strategy.three_categories import load_pool_state
        st = load_pool_state()
        tot = len(st.v_pool)+len(st.t_pool)+len(st.n_pool)
        assert tot == 15, f"应15只, got {tot}"
        print(f"  [PASS] 三分法池已播种: 15 只 (V{len(st.v_pool)}/T{len(st.t_pool)}/N{len(st.n_pool)})")
    except Exception as e:
        print(f"  [WARN] 自动播种异常(可手动 poetry run python seed_pool.py): {type(e).__name__}: {e}")
    print("-"*60)
    print("[SUCCESS] Part B(2/2) UI 部署完成 — 重启 web_app:")
    print("  · 观察池应显示 V/T/N 各5只   · 点'看K线'出红涨绿跌图")
    print("  · agent 名/术语中文化   · 底部'股市早晚报入库'可粘贴日报")
    print("  · 日报也可命令行: poetry run python ingest_briefing_cli.py 日报.md")

if __name__ == "__main__":
    main()
